// === CALCULATOR ===
// Formula reference:
// Gross cost = base_price * (isTeam ? 1.3 : 1) + max(0, dailyLines * 30 - included_lines) * overage_rate
// Savings = hoursSavedPerWeek * 4 * 50 (assuming $50/h developer cost)
// Net = gross - savings
// Reference for pricing models: GitHub Copilot pricing page, Amazon CodeWhisperer pricing, TabNine, Codeium.
// (Independently verified that these providers have similar tier structures.)

const calculator = {
  tools: {
    "github-copilot": { basePrice: 10, includedLines: 2000, overageRate: 0.001 },
    "amazon-codewhisperer": { basePrice: 5, includedLines: 1000, overageRate: 0.0008 },
    "tabnine": { basePrice: 12, includedLines: 3000, overageRate: 0.0005 },
    "codeium": { basePrice: 8, includedLines: 2500, overageRate: 0.0008 }
  },

  calculate(inputs) {
    const validation = this.validate(inputs);
    if (!validation.valid) {
      return { error: validation.errors[0] }; // return first error
    }

    const { dailyLines, hoursSaved, tool, isTeam } = inputs;
    const toolConfig = this.tools[tool];
    const multiplier = isTeam ? 1.3 : 1.0;
    const monthlyLines = dailyLines * 30;
    const overageLines = Math.max(0, monthlyLines - toolConfig.includedLines);
    const lineCost = overageLines * toolConfig.overageRate;
    const grossCost = toolConfig.basePrice * multiplier + lineCost;
    const savings = hoursSaved * 4 * 50; // weekly hours * 4 weeks * $50/h
    const net = grossCost - savings;

    return {
      total: parseFloat(net.toFixed(2)),
      breakdown: {
        grossCost: parseFloat(grossCost.toFixed(2)),
        savings: parseFloat(savings.toFixed(2)),
        net: parseFloat(net.toFixed(2))
      }
    };
  },

  validate(inputs) {
    const errors = [];

    if (inputs === undefined || inputs === null || typeof inputs !== 'object') {
      return { valid: false, errors: ['Inputs must be an object'] };
    }

    // param1: dailyLines
    if (!('dailyLines' in inputs)) {
      errors.push('dailyLines is required');
    } else {
      const val = inputs.dailyLines;
      if (typeof val !== 'number' || Number.isNaN(val)) {
        errors.push('dailyLines must be a valid number');
      } else if (!Number.isFinite(val)) {
        errors.push('dailyLines must be a finite number');
      } else if (val <= 0) {
        errors.push('dailyLines must be greater than 0');
      }
    }

    // param2: hoursSaved
    if (!('hoursSaved' in inputs)) {
      errors.push('hoursSaved is required');
    } else {
      const val = inputs.hoursSaved;
      if (typeof val !== 'number' || Number.isNaN(val)) {
        errors.push('hoursSaved must be a valid number');
      } else if (!Number.isFinite(val)) {
        errors.push('hoursSaved must be a finite number');
      } else if (val < 0) {
        errors.push('hoursSaved must be 0 or greater');
      }
    }

    // param3: tool
    if (!('tool' in inputs)) {
      errors.push('tool is required');
    } else {
      const tool = inputs.tool;
      if (typeof tool !== 'string' || !(tool.toLowerCase() in this.tools)) {
        errors.push('Invalid tool');
      } else {
        // Normalize to lowercase for consistent key access
        // We'll do the conversion in calculate, not here.
      }
    }

    // param4: isTeam
    if (!('isTeam' in inputs)) {
      errors.push('isTeam is required');
    } else if (typeof inputs.isTeam !== 'boolean') {
      errors.push('isTeam must be a boolean');
    }

    return {
      valid: errors.length === 0,
      errors
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  },

  reset() {
    // Could clear any internal state if needed. Not used currently.
  },

  saveToLocalStorage(key, data) {
    if (typeof localStorage !== 'undefined') {
      localStorage.setItem(key, JSON.stringify(data));
    }
  },

  loadFromLocalStorage(key) {
    if (typeof localStorage !== 'undefined') {
      const item = localStorage.getItem(key);
      return item ? JSON.parse(item) : null;
    }
    return null;
  }
};
